const session = $json.body?.data?.object ?? {};

const shipping = session.shipping_details ?? {};
const address = shipping.address ?? {};

if (!shipping.name || !address.line1 || !address.city || !address.postal_code || !address.country) {
  throw new Error('Stripe payload is missing shipping_details fields. Ensure shipping is required in Checkout Session.');
}

return [
  {
    json: {
      stripeEventType: $json.body?.type,
      stripeSessionId: session.id,
      customerEmail: session.customer_details?.email ?? session.customer_email ?? '',
      amountTotalCents: session.amount_total ?? 0,
      currency: session.currency ?? 'usd',
      shipTo: {
        name: shipping.name,
        phone: shipping.phone ?? session.customer_details?.phone ?? '',
        company: '',
        address1: address.line1,
        address2: address.line2 ?? '',
        city: address.city,
        state: address.state ?? '',
        postalCode: address.postal_code,
        country: address.country
      }
    }
  }
];

