const order = $json;
const orderId = order.orderID ?? order.orderId ?? order.id ?? order._id ?? order.data?.orderID ?? order.data?.id;

if (!orderId) {
  throw new Error('Unable to find order ID in Ship.com create order response.');
}

return [{ json: { orderId } }];

const payload = $json;
const prices = payload.Prices ?? payload.prices ?? payload.rates ?? payload.data?.Prices ?? payload.data?.rates ?? [];

if (!Array.isArray(prices) || prices.length === 0) {
  throw new Error('No rates returned from Ship.com shipping-info endpoint.');
}

const scored = prices
  .map((r) => {
    const amount = Number(r.TotalAmount ?? r.totalAmount ?? r.rate ?? r.price ?? r.amount ?? Number.POSITIVE_INFINITY);
    return { amount, raw: r };
  })
  .sort((a, b) => a.amount - b.amount);

const best = scored[0].raw;

const shippingMethod = best.ShippingMethod ?? best.shippingMethod ?? best.method;
const serviceLevel = best.ServiceLevel ?? best.serviceLevel ?? best.service;
const packageID = best.PackageID ?? best.packageID ?? best.packageId;
const rateID = best.RateID ?? best.rateID ?? best.rateId ?? best.id;

if (!shippingMethod || !serviceLevel || !packageID || !rateID) {
  throw new Error('Rate response missing required purchase-label fields (shippingMethod, serviceLevel, packageID, rateID).');
}

return [{
  json: {
    shippingMethod,
    serviceLevel,
    packageID,
    rateID
  }
}];

